func solve(points [][]int64) int64 {
	const mod = int64(1e9 + 7)
	// Group points by y-coordinate
	yMap := make(map[int64][][]int64)
	for _, p := range points {
		y := p[1]
		yMap[y] = append(yMap[y], p)
	}

	var res int64 = 0

	// For each y-coordinate, sort the points by x-coordinate
	for y, ps := range yMap {
		if len(ps) < 2 {
			continue
		}
		sort.Slice(ps, func(i, j int) bool {
			return ps[i][0] < ps[j][0]
		})
	}

	// Iterate all pairs of y-coordinates (y1, y2)
	yList := make([]int64, 0, len(yMap))
	for y := range yMap {
		yList = append(yList, y)
	}
	sort.Slice(yList, func(i, j int) bool {
		return yList[i] < yList[j]
	})

	for i := 0; i < len(yList); i++ {
		y1 := yList[i]
		ps1 := yMap[y1]
		if len(ps1) < 2 {
			continue
		}
		for j := i + 1; j < len(yList); j++ {
			y2 := yList[j]
			ps2 := yMap[y2]
			if len(ps2) < 2 {
				continue
			}

			// Find common x-coordinates between ps1 and ps2
			// Since both are sorted, we can use two pointers
			var common []int64
			a, b := 0, 0
			for a < len(ps1) && b < len(ps2) {
				x1 := ps1[a][0]
				x2 := ps2[b][0]
				if x1 == x2 {
					common = append(common, x1)
					a++
					b++
				} else if x1 < x2 {
					a++
				} else {
					b++
				}
			}

			if len(common) >= 2 {
				// Number of ways to choose 2 from common x's is C(k, 2)
				k := int64(len(common))
				res = (res + k*(k-1)/2) % mod
			}
		}
	}

	return res
}
