        // Then for any two y's with at least two x's, the number of trapezoids is C(m, 2) * C(k, 2)
        // where m and k are the counts of x's in the two y's
        // So first, we need to count the number of x pairs for each y
        cnt := n * (n - 1) / 2
        res += cnt * (cnt - 1) / 2
        res %= mod
    }

    // Now handle the case where the two parallel sides are from different y's
    // We need to find all pairs of y's that have at least two x's
    ys := make([]int64, 0, len(yToXs))
    for y := range yToXs {
        if len(yToXs[y]) >= 2 {
            ys = append(ys, y)
        }
