	const mod = int64(1e9 + 7)
	// Group points by y-coordinate
	yMap := make(map[int64][]int64)
	for _, point := range points {
		x, y := point[0], point[1]
		yMap[y] = append(yMap[y], x)
	}

	// Sort x-coordinates for each y
	for y := range yMap {
		sort.Slice(yMap[y], func(i, j int) bool {
			return yMap[y][i] < yMap[y][j]
		})
	}

	var res int64

	// Iterate all pairs of y-coordinates (y1 < y2)
	yList := make([]int64, 0, len(yMap))
	for y := range yMap {
		yList = append(yList, y)
	}
	sort.Slice(yList, func(i, j int) bool {
		return yList[i] < yList[j]
	})

	for i := 0; i < len(yList); i++ {
		y1 := yList[i]
		xs1 := yMap[y1]
		m := len(xs1)
		if m < 2 {
			continue
		}
		for j := i + 1; j < len(yList); j++ {
			y2 := yList[j]
			xs2 := yMap[y2]
			n := len(xs2)
			if n < 2 {
				continue
			}
			// Find common x pairs between xs1 and xs2
			// Using two pointers to find common x values
			common := make([]int64, 0)
			p1, p2 := 0, 0
			for p1 < m && p2 < n {
				if xs1[p1] == xs2[p2] {
					common = append(common, xs1[p1])
					p1++
					p2++
				} else if xs1[p1] < xs2[p2] {
					p1++
				} else {
					p2++
				}
			}
			k := int64(len(common))
			if k >= 2 {
				// C(k, 2) * C(m - k, 2) + C(k, 2) * (m - k) * (n - k) + C(k, 2) * C(n - k, 2)
				// But actually, it's C(k, 2) * (C(m, 2) + C(n, 2) - C(k, 2))
				// Or more accurately, C(k, 2) * (C(m, 2) + C(n, 2) - C(k, 2)) is not correct
				// The correct formula is C(k, 2) * (C(m - k, 2) + (m - k) * (n - k) + C(n - k, 2)) + C(k, 3) * ( (m - k) + (n - k) ) + C(k, 4)
				// But for the problem, we can simplify to C(k, 2) * (C(m, 2) + C(n, 2) - C(k, 2)) is not accurate
				// So we need to compute all possible combinations:
				// Total trapezoids: C(m, 2) * C(n, 2) - C(k, 2) * C(k, 2)
				// But actually, the correct formula is C(m, 2) * C(n, 2) - C(k, 2) * C(k, 2)
				// But the problem requires at least one pair of horizontal edges, so we need to subtract the cases where both pairs are vertical
				// So the formula is C(m, 2) * C(n, 2) - C(k, 2) * C(k, 2)
				c1 := m * (m - 1) / 2
				c2 := n * (n - 1) / 2
				ck := k * (k - 1) / 2
				res += (int64(c1) * int64(c2) - int64(ck) * int64(ck)) % mod
				res %= mod
			} else {
