func solve(points [][]int64) int64 {
	const mod = int64(1e9 + 7)
	yToXs := make(map[int64][]int64)
	for _, point := range points {
		x, y := point[0], point[1]
		yToXs[y] = append(yToXs[y], x)
	}

	var res int64
	for y, xs := range yToXs {
		if len(xs) < 2 {
			continue
		}
		sort.Slice(xs, func(i, j int) bool { return xs[i] < xs[j] })
		n := len(xs)
		for i := 0; i < n; i++ {
			for j := i + 1; j < n; j++ {
				x1, x2 := xs[i], xs[j]
				// For each other y, count the number of pairs (x3, x4) where x3 < x4 and x3 - x4 = x1 - x2
				// So x4 - x3 = x2 - x1
				dx := x2 - x1
				for otherY, otherXs := range yToXs {
					if otherY == y {
						continue
					}
					if len(otherXs) < 2 {
						continue
					}
					m := len(otherXs)
					var cnt int64
					left, right := 0, 1
					for left < m {
						for right < m && otherXs[right]-otherXs[left] < dx {
							right++
						}
						if right < m && otherXs[right]-otherXs[left] == dx {
							cnt++
						}
						left++
						if right == left {
							right++
						}
					}
					res = (res + cnt) % mod
				}
			}
		}
	}
	return res % mod
}
