func solve(points [][]int64) int64 {
	const mod = int64(1e9 + 7)
	// Group points by y-coordinate
	yMap := make(map[int64][][]int64)
	for _, p := range points {
		y := p[1]
		yMap[y] = append(yMap[y], p)
	}

	var res int64
	// For each y-coordinate with at least 2 points (to form a horizontal line)
	for y, list := range yMap {
		if len(list) < 2 {
			continue
		}
		// Sort points with same y by x-coordinate
		sort.Slice(list, func(i, j int) bool {
			return list[i][0] < list[j][0]
		})
		// For each other y-coordinate with at least 2 points
		for otherY, otherList := range yMap {
			if otherY <= y || len(otherList) < 2 {
				continue
			}
			// Sort otherList by x-coordinate
			sort.Slice(otherList, func(i, j int) bool {
				return otherList[i][0] < otherList[j][0]
			})
			// Now, for each pair of points in list and otherList, we can form trapezoids
			// The number of trapezoids is C(m, 2) * C(n, 2), where m and n are the counts of points in list and otherList
			m := int64(len(list))
			n := int64(len(otherList))
			res = (res + (m*(m-1)/2)*(n*(n-1)/2)) % mod
		}
	}
	return res
}
