    for _, xs := range yToXs {
        if len(xs) < 2 {
            continue
        }
        sort.Slice(xs, func(i, j int) bool { return xs[i] < xs[j] })
        n := int64(len(xs))
        // C(n, 2) = n*(n-1)/2
        res = (res + n*(n-1)/2) % mod
    }

    total := int64(0)
    for _, xs := range yToXs {
        n := int64(len(xs))
        if n >= 2 {
            // C(n, 2) = n*(n-1)/2
            total = (total + n*(n-1)/2) % mod
        }
    }
    // The result is total choose 2 minus sum of C(cnt, 2) choose 2 for each y
    // But since the problem requires at least one pair of horizontal edges, it's equivalent to:
    // For all possible combinations of two pairs of points with the same y, subtract the cases where all four points are on the same y
    // So res = C(total, 2) - sum over y (C(cnt[y], 2) choose 2)
    var sameY int64
    for _, xs := range yToXs {
        n := int64(len(xs))
        if n >= 2 {
            // C(n, 2) = n*(n-1)/2
            c := n * (n - 1) / 2
            sameY = (sameY + c*(c-1)/2) % mod
        }
    }
    if total < 2 {
        return 0
    }
    res = (total*(total-1)/2 % mod - sameY + mod) % mod
    return res
}
