        prefixX := make([]int64, n+1)
        prefixX2 := make([]int64, n+1)
        for i := 0; i < n; i++ {
            prefixX[i+1] = (prefixX[i] + sortedXs[i]) % mod
            prefixX2[i+1] = (prefixX2[i] + sortedXs[i]*sortedXs[i]) % mod
