func solve(points [][]int64) int64 {
    const mod = int64(1e9 + 7)
    yToXs := make(map[int64][]int64)
    for _, p := range points {
        x, y := p[0], p[1]
        yToXs[y] = append(yToXs[y], x)
    }

    var res int64
    for y, xs := range yToXs {
        if len(xs) < 2 {
            continue
        }
        // Sort the xs for this y
        sortedXs := make([]int64, len(xs))
        copy(sortedXs, xs)
        sort.Slice(sortedXs, func(i, j int) bool { return sortedXs[i] < sortedXs[j] })

        // Precompute prefix sums of x and x^2
        n := len(sortedXs)
        prefixX := make([]int64, n+1)
        prefixX2 := make([]int64, n+1)
        for i := 0; i < n; i++ {
            prefixX[i+1] = (prefixX[i] + sortedXs[i]) % mod
            prefixX2[i+1] = (prefixX2[i] + sortedXs[i]*sortedXs[i]) % mod
        }

        // For each pair (i,j) where i < j, compute the contribution
        for j := 1; j < n; j++ {
            xj := sortedXs[j]
            // Sum over i < j: (xj - xi) * (j - i - 1)
            // = xj * (j*(j-1)/2) - sum_{i<j} xi * (j - i - 1)
            // To compute sum_{i<j} xi * (j - i - 1), we can rewrite as:
            // sum_{i=0}^{j-1} xi * (j - i - 1) = sum_{k=0}^{j-1} xi * k where k = j-i-1
            // But it's easier to compute as:
            // sum_{i=0}^{j-1} xi * (j-1 - i) = sum_{i=0}^{j-1} xi*(j-1) - sum_{i=0}^{j-1} xi*i
            // = (j-1)*prefixX[j] - sum_{i=0}^{j-1} xi*i
            // sum_{i=0}^{j-1} xi*i can be computed using prefix sums of xi*i
            // But since we don't have that, we need another way.
            // Alternatively, note that:
            // sum_{i=0}^{j-1} xi*(j-1 -i) = sum_{i=0}^{j-1} xi*(j-1) - sum_{i=0}^{j-1} xi*i
            // = (j-1)*prefixX[j] - sum_{i=0}^{j-1} xi*i
            // sum_{i=0}^{j-1} xi*i can be computed as:
            // sum_{i=0}^{j-1} xi*i = sum_{i=1}^{j-1} xi*i (since i=0 term is 0)
            // But without precomputing, it's O(j) per j, which is O(n^2) total.
            // To optimize, we can find a way to compute this sum using prefix sums.
            // However, it's not straightforward, so we'll proceed with the O(n^2) approach for now.
            // But given the constraints (n up to 1e5), O(n^2) is not feasible.
            // So we need a better approach.
            // Let's think differently: for a given y, the number of trapezoids is C(m, 4) where m is the number of points on y.
            // But this is not correct because trapezoids can be formed with two pairs of parallel sides, not necessarily horizontal.
            // So we need to find all pairs of parallel sides.
            // The correct approach is to group points by y, then for each y with m points, the number of trapezoids with both horizontal sides on y is C(m, 2) * C(k, 2) where k is the number of points on another y.
            // But this is also not correct because the other two points can be on any y, not necessarily the same.
            // The correct approach is to find all pairs of y's that have at least two points, then for each such pair (y1, y2), the number of trapezoids is C(m, 2) * C(k, 2) where m is the number of points on y1 and k is the number of points on y2.
            // If y1 == y2, then it's C(m, 4) since we need to choose 4 points from the same y.
            // So the total is sum_{y} C(m_y, 4) + sum_{y1 < y2} C(m_y1, 2) * C(m_y2, 2)
            // This can be computed efficiently.
            // So let's implement this.
        }
    }

    // Now compute the total as described above
    ys := make([]int64, 0, len(yToXs))
    for y := range yToXs {
        ys = append(ys, y)
    }
    sort.Slice(ys, func(i, j int) bool { return ys[i] < ys[j] })

    var total int64
    // First, compute sum C(m, 4)
    for _, y := range ys {
        m := int64(len(yToXs[y]))
        if m >= 4 {
            total = (total + m*(m-1)*(m-2)*(m-3)/24) % mod
        }
    }
    // Then, compute sum_{y1 < y2} C(m_y1, 2) * C(m_y2, 2)
    // To compute this efficiently, we can compute sum C(m, 2) for all y, then the sum is (sum C(m, 2))^2 - sum C(m, 2)^2, all divided by 2
    var sumC2 int64
    var sumC2Sq int64
    for _, y := range ys {
        m := int64(len(yToXs[y]))
        if m >= 2 {
            c2 := m * (m - 1) / 2 % mod
            sumC2 = (sumC2 + c2) % mod
            sumC2Sq = (sumC2Sq + c2*c2) % mod
        }
    }
    cross := (sumC2*sumC2 - sumC2Sq) % mod
    if cross < 0 {
        cross += mod
    }
    cross = cross * ((mod + 1) / 2) % mod // divide by 2 mod 1e9+7
    total = (total + cross) % mod

    return total
}
