				} else {
					b++
				}
			}

			if len(common) >= 2 {
				// Number of ways to choose 2 from common x's: C(k, 2)
				k := int64(len(common))
				c := k * (k - 1) / 2
				// Number of ways to choose 2 from ps1 (excluding common x's): C(m, 2)
				m := int64(len(ps1) - len(common))
				// Number of ways to choose 2 from ps2 (excluding common x's): C(n, 2)
				n := int64(len(ps2) - len(common))
				// Total combinations: c * (C(m, 2) + C(n, 2) + m*n)
				total := c * (m*(m-1)/2 + n*(n-1)/2 + m*n)
				res = (res + total) % mod
			}
		}
	}

	return res % mod
