package main

import (
	"sort"
)

func solve(points [][]int64) int64 {
	const mod = int64(1e9 + 7)
	yToXs := make(map[int64][]int64)
	for _, point := range points {
		x, y := point[0], point[1]
		yToXs[y] = append(yToXs[y], x)
	}

	var res int64
	for y, xs := range yToXs {
		if len(xs) < 2 {
			continue
		}
		sort.Slice(xs, func(i, j int) bool { return xs[i] < xs[j] })
		n := len(xs)
		for i := 0; i < n; i++ {
			for j := i + 1; j < n; j++ {
				x1, x2 := xs[i], xs[j]
				// For each pair (x1, x2) on this y, count the number of pairs (x3, x4) on another y
				// where x3 < x4 and (x3, x4) != (x1, x2)
				// The total is (C(m, 2) for each other y) - 1 if (x3, x4) exists on another y
				// But to optimize, we can precompute for each (x1, x2) how many times it appears in other y's
				// So the answer is sum over all y' != y of C(count[y'][x1,x2], 2)
				// But we need to count how many y' have both x1 and x2
				// So we can build a map from (x1, x2) to the count of y's that have both x1 and x2
			}
		}
	}

	// To optimize, we need to count for each pair (x1, x2) how many y's have both x1 and x2
	pairCount := make(map[[2]int64]int64)
	for y, xs := range yToXs {
		sort.Slice(xs, func(i, j int) bool { return xs[i] < xs[j] })
		n := len(xs)
		for i := 0; i < n; i++ {
			for j := i + 1; j < n; j++ {
				x1, x2 := xs[i], xs[j]
				pair := [2]int64{x1, x2}
				pairCount[pair]++
			}
		}
	}

	res = 0
	for _, cnt := range pairCount {
		if cnt >= 2 {
			res += cnt * (cnt - 1) / 2
			res %= mod
		}
	}

	return res
}
